#############################################################################
#### functions for analysis
#### a function to calculate regional seq depth
windows_methyl_form <- function(genome_slide_bed, seq_depth_file) {
  fraction_modified_windows <- as.data.frame(matrix(nrow=0, ncol = 7))
  colnames(fraction_modified_windows) <- c("chrom", "start", "end", "phase", "replicate",
                                           "sum_seq_depth","genus")
  
  n_iter <- length(seq_len(nrow(genome_slide_bed)))
  
  pb <- txtProgressBar(min = 0,      # Minimum value of the progress bar
                       max = n_iter, # Maximum value of the progress bar
                       style = 3,    # Progress bar style (also available style = 1 and style = 2)
                       width = 50,   # Progress bar width. Defaults to getOption("width")
                       char = "=")
  
  for (i in seq_len(nrow(genome_slide_bed))){
    start_label <- as.integer(genome_slide_bed[i, "start"])
    end_label <- as.integer(genome_slide_bed[i, "end"])
    chromosome <- as.character(genome_slide_bed[i, "chromosome"])
    
    inter_form <- subset(seq_depth_file,
                         seq_depth_file$position >= start_label & seq_depth_file$position < end_label & seq_depth_file$chrom == chromosome)
    
    inter_form_summary <- inter_form %>%
      group_by(chrom, phase, genus, replicate_id) %>%
      summarise(sum_seq_depth = sum(seq_depth), .groups = "drop")
    
    inter_form_summary$start <- start_label
    inter_form_summary$end <- end_label
    
    fraction_modified_windows <- rbind(fraction_modified_windows, inter_form_summary)
    setTxtProgressBar(pb, i)
  }
  cat("\n almost there")
  close(pb) # Close the connection
  return(fraction_modified_windows)
}

#### a function to calculate regional dna start site
windows_dna_site_form <- function(genome_slide_bed, dna_site_file) {
  fraction_modified_windows <- as.data.frame(matrix(nrow=0, ncol = 7))
  colnames(fraction_modified_windows) <- c("chromosome", "start", "end", "phase", "replicate",
                                           "sum_dan_site", "sum_end_site")
  
  n_iter <- length(seq_len(nrow(genome_slide_bed)))
  
  pb <- txtProgressBar(min = 0,      # Minimum value of the progress bar
                       max = n_iter, # Maximum value of the progress bar
                       style = 3,    # Progress bar style (also available style = 1 and style = 2)
                       width = 50,   # Progress bar width. Defaults to getOption("width")
                       char = "=")
  
  for (i in seq_len(nrow(genome_slide_bed))){
    start_label <- as.integer(genome_slide_bed[i, "start"])
    end_label <- as.integer(genome_slide_bed[i, "end"])
    chromosome <- as.character(genome_slide_bed[i, "chromosome"])
    
    inter_form_start <- subset(dna_site_file,
                               dna_site_file$start >= start_label & dna_site_file$start < end_label & dna_site_file$chromosome == chromosome)
    
    inter_form_end <- subset(dna_site_file,
                             dna_site_file$end >= start_label & dna_site_file$end < end_label & dna_site_file$chromosome == chromosome)
    
    inter_form_start_summary <- inter_form_start %>%
      group_by(chromosome, phase, replicate) %>%
      summarise(sum_start_site = n(), .groups = "drop")
    
    inter_form_end_summary <- inter_form_end %>%
      group_by(chromosome, phase, replicate) %>%
      summarise(sum_end_site = n(), .groups = "drop")
    
    inter_form_start_summary$start <- start_label
    inter_form_start_summary$end <- end_label
    
    inter_form_end_summary$start <- start_label
    inter_form_end_summary$end <- end_label
    
    inter_form_start_summary <- inter_form_start_summary%>%
      mutate(unique_id=paste(chromosome, phase, replicate, start, end, sep = "_"))
    
    inter_form_end_summary <- inter_form_end_summary%>%
      mutate(unique_id=paste(chromosome, phase, replicate, start, end, sep = "_"))
    
    inter_form_summary <- inter_form_start_summary %>%
      inner_join(inter_form_end_summary[,c("unique_id", "sum_end_site")], by="unique_id")
    
    fraction_modified_windows <- rbind(fraction_modified_windows, inter_form_summary)
    setTxtProgressBar(pb, i)
  }
  cat("\n almost there")
  close(pb) # Close the connection
  return(fraction_modified_windows)
}

#### a function to calculate the seq depth in oriC, ter, and other regions
region_seq_form <- function(genome_slide_bed, seq_depth_file, region_name) {
  fraction_modified_windows <- as.data.frame(matrix(nrow=0, ncol = 7))
  colnames(fraction_modified_windows) <- c("chrom", "start", "end", "phase", "replicate",
                                           "sum_seq_depth","genus")
  replicate_name_list <- unique(seq_depth_file$replicate)
  
  inter_addition_form <- as.data.frame(matrix(nrow=0, ncol = 10))
  colnames(inter_addition_form) <- c("chrom", "start", "end", "phase", "replicate",
                                     "sum_seq_depth","genus")
  
  n_iter <- length(seq_len(nrow(genome_slide_bed)))
  
  pb <- txtProgressBar(min = 0,      # Minimum value of the progress bar
                       max = n_iter, # Maximum value of the progress bar
                       style = 3,    # Progress bar style (also available style = 1 and style = 2)
                       width = 50,   # Progress bar width. Defaults to getOption("width")
                       char = "=")
  
  for (i in seq_len(nrow(genome_slide_bed))){
    start_label <- as.integer(genome_slide_bed[i, "start"])
    end_label <- as.integer(genome_slide_bed[i, "end"])
    chromosome <- as.character(genome_slide_bed[i, "chromosome"])
    
    inter_form <- subset(seq_depth_file,
                         seq_depth_file$position >= start_label & seq_depth_file$position < end_label & seq_depth_file$chrom == chromosome)
    
    inter_form_summary <- inter_form %>%
      group_by(chrom, phase, genus, replicate_id) %>%
      summarise(sum_seq_depth = sum(seq_depth), .groups = "drop")
    
    inter_form_summary$start <- start_label
    inter_form_summary$end <- end_label
    inter_form_summary$region <- region_name
    
    fraction_modified_windows <- rbind(fraction_modified_windows, inter_form_summary)
    setTxtProgressBar(pb, i)
  }
  cat("\n almost there")
  close(pb) # Close the connection
  return(fraction_modified_windows)
}

