#### perform seq depth analysis using functions
ecoli_seq_depth_window <- windows_methyl_form(ecoli_genome_slide, ecoli_seq_depth)
lacidophilus_seq_depth_window <- windows_methyl_form(lacidophilus_genome_slide, lacidophilus_seq_depth)

ecoli_ter_middle <- (2115426+2115454)/2
lacidophilus_ter_middle <- 759661

ecoli_origin_middle <- (4719203+4179580)/2

lacidophilus_origin_1_middle <- (1644596+1645071)/2
lacidophilus_origin_2_middle <- (1646440+1646616)/2

#### e. coli
ecoli_seq_depth_summary_wider <- ecoli_seq_depth_window %>%
  pivot_wider(names_from = phase, values_from = sum_seq_depth) %>%
  mutate(differential_seq_depth=(stationary+1)/(exponential+1),
         log2_differential_seq_depth=log2((stationary+1)/(exponential+1)))

ecoli_seq_depth_summary <- ecoli_seq_depth_summary_wider %>%
  group_by(chrom, genus, start, end) %>%
  summarise(mean_exp_depth=mean(exponential/(end-start)),
            mean_sta_depth=mean(stationary/(end-start)),
            sd_exp_depth=sd(exponential/(end-start)),
            sd_sta_depth=sd(stationary/(end-start)),
            mean_log2_seq_depth=mean(log2_differential_seq_depth), 
            sd_log2_seq_depth=sd(log2_differential_seq_depth), .groups = "drop") %>%
  mutate(rel_position_ter=((start+end)/2)-ecoli_ter_middle,
         rel_position_origin_1=((start+end)/2)-ecoli_origin_middle,
         rel_position_origin_2=((start+end)/2)-ecoli_origin_middle)

#### l. acidophilus
lacidophilus_seq_depth_wider <- lacidophilus_seq_depth_window %>%
  pivot_wider(names_from = phase, values_from = sum_seq_depth) %>%
  mutate(differential_seq_depth=(stationary+1)/(exponential+1),
         log2_differential_seq_depth=log2((stationary+1)/(exponential+1)))

lacidophilus_seq_depth_summary <- lacidophilus_seq_depth_wider %>%
  group_by(chrom, genus, start, end) %>%
  summarise(mean_exp_depth=mean(exponential/(end-start)),
            mean_sta_depth=mean(stationary/(end-start)),
            sd_exp_depth=sd(exponential/(end-start)),
            sd_sta_depth=sd(stationary/(end-start)),
            mean_log2_seq_depth=mean(log2_differential_seq_depth), 
            sd_log2_seq_depth=sd(log2_differential_seq_depth), .groups = "drop") %>%
  mutate(rel_position_ter=((start+end)/2)-lacidophilus_ter_middle,
         rel_position_origin_1=((start+end)/2)-lacidophilus_origin_1_middle,
         rel_position_origin_2=((start+end)/2)-lacidophilus_origin_2_middle)

ecoli_lacidophilus_seq_depth_summary <- rbind(ecoli_seq_depth_summary, lacidophilus_seq_depth_summary)

ecoli_lacidophilus_seq_depth_summary <- ecoli_lacidophilus_seq_depth_summary %>%
  mutate(direction_ter=ifelse(rel_position_ter>=0, "upstream", "downstream"),
         direction_rel_position_origin_1=ifelse(rel_position_origin_1>=0, "upstream", "downstream"),
         direction_rel_position_origin_2=ifelse(rel_position_origin_2>=0, "upstream", "downstream"))

ecoli_lacidophilus_seq_depth <- rbind(ecoli_seq_depth_summary_wider, lacidophilus_seq_depth_wider)

