#### perform read start site analysis using functions
setwd("")
ecoli_dna_site <- fread("ecoli_dna_replication_start.tsv",sep="\t", header=TRUE)
lacidophilus_dna_site <- fread("lacidophilus_dna_replication_start.tsv",sep="\t", header=TRUE)

options(scipen=999)

ecoli_dna_site_longer <- ecoli_dna_site %>%
  pivot_longer(cols = c("start", "end"),
               names_to = "replication_site",
               values_to = "position") %>%
  filter(chromosome=="NC_002695.2",
         replicate %in% c("replicate_1", "replicate_2", "replicate_3"))

lacidophilus_dna_site_longer <- lacidophilus_dna_site %>%
  pivot_longer(cols = c("start", "end"),
               names_to = "replication_site",
               values_to = "position")

ecoli_seq_depth_oric <- region_seq_form(ecoli_oriC, ecoli_seq_depth, "oriC")
ecoli_seq_depth_ter <- region_seq_form(ecoli_ter, ecoli_seq_depth, "ter")
ecoli_seq_depth_others <- region_seq_form(ecoli_other_regions, ecoli_seq_depth, "others")

ecoli_seq_depth_all_regions <- rbind(ecoli_seq_depth_oric, ecoli_seq_depth_ter, ecoli_seq_depth_others)
ecoli_seq_depth_all_regions_summary <- ecoli_seq_depth_all_regions %>%
  group_by(chrom, phase, genus, region) %>%
  summarise(mean_sum_seq_depth = mean(sum_seq_depth), .groups = "drop")

